var theGameFix = {
    "cmd_server": "set \"gamedrive=D:\"\r\nset \"NetShareName=iCafeCloudShare\"\r\nset \"NetShareSource=M:\\iCafeCloudShare\"\r\nset \"SaveShaders=1\"\r\nset \"GameSave=1\"\r\nset \"ICafeHDD=0\"\r\ncall :netshare_server \"%NetShareSource%\" \"%NetShareName%\" \"FULL\"\r\n\r\nrem ==== GameFix for FiveM ====\r\n\ntasklist | find \"FiveM.exe\"\nif %errorlevel% equ 0 (\n\ttaskkill /F /IM FiveM.exe\n\ttimeout 2\n)\n\ncall :do_mklink \"%LocalAppData%\" \"FiveM\" 1 \"FiveM\\LocalAppData\"\n\n\n\r\n\r\nrem ==== GameFix for Rockstar ====\r\n\ntasklist | find /I \"SocialClubHelper.exe\"\nif %errorlevel% equ 0 (\n\ttaskkill /F /IM SocialClubHelper.exe\n\ttimeout 2\n)\nreg export HKLM\\SOFTWARE\\WOW6432Node\\Rockstar Games \"D:\\Launchers\\Rockstar Games\\Launcher\\rockstar.reg\" /y\ncall :do_mklink \"%LocalAppData%\" \"Rockstar Games\" 1 \"Rockstar\\APPDATA\\Local\"\ncall :do_mklink \"%ProgramData%\" \"Rockstar Games\" 1 \"Rockstar\\ProgramData\"\n\r\n\r\nrem ==== GameFix for Uplay ====\r\n\ntasklist | find /I \"upc.exe\"\nif %errorlevel% equ 0 (\n\ttaskkill /F /IM upc.exe\n\ttimeout 2\n)\ncall :do_mklink \"%LocalAppData%\" \"Ubisoft Game Launcher\" 1 \"Uplay\\APPDATA\\Local\"\ncall :do_mklink \"%ProgramData%\" \"Ubisoft\" 1 \"Uplay\\ProgramData\"\n\r\n\r\nrem ==== GameFix for iCafeMenu ====\r\nif %SaveShaders% equ 1 (\r\n\tcall :netshare_server \"%NetShareSource%\" \"%NetShareName%\" \"FULL\"\r\n\tif not exist \"%NetShareSource%\\pcs\" (\r\n\t\tmkdir \"%NetShareSource%\\pcs\"\r\n\t)\r\n\tgoto icafemenu_next\r\n)\r\n\r\nif %GameSave% equ 1 (\r\n\tcall :netshare_server \"%NetShareSource%\" \"%NetShareName%\" \"FULL\"\r\n\tif not exist \"%NetShareSource%\\users\" (\r\n\t\tmkdir \"%NetShareSource%\\users\"\r\n\t)\r\n\tgoto icafemenu_next\r\n)\r\n\r\n:icafemenu_next\r\n\r\nif %ICafeHDD% equ 1 (\r\n\tcall :netshare_server \"D:\\Apps\\iCafeMenu\" \"iCafeMenu\" \"READ\"\r\n)\r\n\r\n\r\ngoto do_mklink_end\r\n:do_mklink\r\n:: do_mklink \"source_path\" \"source_name\" \"source_copy\" \"target_path\"\r\nset \"source_path=%~1\"\r\nset \"source_name=%~2\"\r\nset \"source_copy=%~3\"\r\nset \"target_path=%~4\"\r\n:: if not absolute path\r\nIf \"%target_path:~1,1%\" equ \":\" goto mklink_next\r\nIf \"%target_path:~0,2%\" equ \"\\\\\" goto mklink_next\r\nset \"target_path=%gamedrive%\\GameFixes\\%target_path%\"\r\n:mklink_next\r\n2>nul dir /AL /B \"%source_path%\" | find \"%source_name%\"\r\nIf %errorlevel% equ 0 (\r\n\trmdir \"%source_path%\\%source_name%\"\r\n)\r\n2>nul dir /AD /B \"%source_path%\" | find \"%source_name%\"\r\nIf %errorlevel% equ 0 (\r\n\tIf %source_copy% equ 1 (\r\n\t\txcopy \"%source_path%\\%source_name%\\*\" \"%target_path%\\\" /y /s /e\r\n\t)\r\n\trmdir \"%source_path%\\%source_name%\" /s /q\r\n)\r\n\r\nIf not exist \"%target_path%\\\" ( mkdir \"%target_path%\\\" )\r\nIf exist \"%target_path%\\\" (\r\n\tif not exist \"%source_path%\\%source_name%\\\" (\r\n\t\tmkdir \"%source_path%\\%source_name%\\\"\r\n\t\trmdir \"%source_path%\\%source_name%\\\"\r\n\t)\r\n\tmklink /D \"%source_path%\\%source_name%\\\" \"%target_path%\\\"\r\n)\r\nexit /b 0\r\n:do_mklink_end\r\n\r\ngoto do_everyone_name_end\r\n:do_everyone_name\r\n:: https://groups.google.com/g/alt.msdos.batch.nt/c/__xbYef0Z_Y\r\nset \"everyone_name=Everyone\"\r\nfor /f \"tokens=1* delims= \" %%a in ('whoami /groups ^| find \"S-1-1-0\"') do ( set \"everyone_name=%%a\" )\r\n:loop_do_everyone_name_end\r\nexit /b 0\r\n:do_everyone_name_end\r\n\r\ngoto do_gamefix_permission_end\r\n:do_gamefix_permission\r\n:: call :do_everyone_name\r\nICACLS \"%gamedrive%\\GameFixes\" /grant:r \"*S-1-1-0\":(OI)(CI)F /inheritance:e /T /Q\r\nexit /b 0\r\n:do_gamefix_permission_end\r\n\r\ngoto create_desktop_shortcut_end\r\n:create_desktop_shortcut\r\nset \"shortcut_name=%~1\"\r\nset \"shortcut_exe_path=%~2\"\r\nset \"shortcut_work_path=%~3\"\r\n\r\necho On Error Resume Next > \"%~dp0CreateShortcut.vbs\"\r\necho Set WshShell = WScript.CreateObject(\"WScript.Shell\") >> \"%~dp0CreateShortcut.vbs\"\r\necho strDesktop = WshShell.SpecialFolders(\"Desktop\") >> \"%~dp0CreateShortcut.vbs\"\r\necho set oShellLink = WshShell.CreateShortcut(strDesktop ^& \"\\\" ^& \"%shortcut_name%\" ^& \".lnk\") >> \"%~dp0CreateShortcut.vbs\"\r\necho oShellLink.TargetPath = \"%shortcut_exe_path%\" >> \"%~dp0CreateShortcut.vbs\"\r\necho oShellLink.Description = \"%shortcut_name%\" >> \"%~dp0CreateShortcut.vbs\"\r\necho oShellLink.WorkingDirectory = \"%shortcut_work_path%\" >> \"%~dp0CreateShortcut.vbs\"\r\necho oShellLink.Save >> \"%~dp0CreateShortcut.vbs\"\r\n\r\ncall wscript -e:vbs \"%~dp0CreateShortcut.vbs\"\r\nexit /b 0\r\n:create_desktop_shortcut_end\r\n\r\ngoto replace_file_string_end\r\n:replace_file_string\r\nset \"file_path=%~1\"\r\nset \"file_string=%~2\"\r\nset \"file_replace=%~3\"\r\necho On Error Resume Next > \"%~dp0ReplaceFileString.vbs\"\r\necho Dim Fso, textFile, textString >> \"%~dp0ReplaceFileString.vbs\"\r\necho Set Fso = CreateObject(\"Scripting.FileSystemObject\") >> \"%~dp0ReplaceFileString.vbs\"\r\necho Set textFile = Fso.OpenTextFile(\"%file_path%\", 1) >> \"%~dp0ReplaceFileString.vbs\"\r\necho textString = Replace(textFile.ReadAll, \"%file_string%\", \"%file_replace%\") >> \"%~dp0ReplaceFileString.vbs\"\r\necho textFile.Close >> \"%~dp0ReplaceFileString.vbs\"\r\necho Set textFile = Fso.OpenTextFile(\"%file_path%\", 2) >> \"%~dp0ReplaceFileString.vbs\"\r\necho textFile.Write textString >> \"%~dp0ReplaceFileString.vbs\"\r\necho textFile.Close >> \"%~dp0ReplaceFileString.vbs\"\r\n\r\ncall wscript -e:vbs \"%~dp0ReplaceFileString.vbs\"\r\nexit /b 0\r\n:replace_file_string_end\r\n\r\n\r\ngoto netshare_client_end\r\n:netshare_client\r\nset \"server_ip=%~1\"\r\ncall :fix_win11_24H2\r\n:network_store_interface\r\nREM Network Store Interface Service for client\r\n2>nul sc query | find /i \"SERVICE_NAME: nsi\"\r\nif %errorlevel% equ 0 (\r\n\tgoto workstation_service\r\n) else (\r\n\tgoto start_nsi_service\r\n)\r\n\r\n:start_nsi_service\r\n2>nul sc config nsi start= AUTO\r\n2>nul net start nsi\r\n\r\n:workstation_service\r\nREM Workstation\r\n2>nul sc query | find /i \"SERVICE_NAME: LanmanWorkstation\"\r\nif %errorlevel% equ 0 (\r\n\tgoto netshare_exit\r\n) else (\r\n\tgoto start_workstation\r\n)\r\n\r\n:start_workstation\r\n2>nul sc config LanmanWorkstation start= AUTO\r\n2>nul net start LanmanWorkstation\r\n\r\n:netshare_exit\r\nfsutil behavior set SymlinkEvaluation L2R:1\r\npowershell -command \"cmdkey /add:%server_ip% /user:$((Get-LocalUser | Where-Object SID -like '*-501').Name)\" \r\nexit /b 0\r\n:netshare_client_end\r\n\r\ngoto netshare_server_end\r\n:netshare_server\r\nREM Netshare Required Services for server\r\n:: call :netshare_server \"source\" \"target\" \"permission\"\r\nset \"netshare_source=%~1\"\r\nset \"netshare_target=%~2\"\r\nset \"netshare_permission=%~3\"\r\n\r\nIf not exist \"%netshare_source%\" ( mkdir \"%netshare_source%\" )\r\n\r\ncall :fix_win11_24H2\r\n\r\n:rpc_endpoint_mapper\r\nREM RPC Endpoint Mapper\r\n2>nul sc query | find /i \"SERVICE_NAME: RpcEptMapper\"\r\nif not errorlevel 1 (goto dcom_server_process_launcher) else goto start_rpc_mapper_service\r\n\r\n:start_rpc_mapper_service\r\n2>nul sc config nsi start= AUTO\r\n2>nul net start nsi\r\n\r\n:dcom_server_process_launcher\r\nREM DCOM Server Process Launcher\r\n2>nul sc query | find /i \"SERVICE_NAME: DcomLaunch\"\r\nif not errorlevel 1 (goto remote_procedure_call) else goto start_dcom_service\r\n\r\n:start_dcom_service\r\n2>nul sc config DcomLaunch start= AUTO\r\n2>nul net start DcomLaunch\r\n\r\n:remote_procedure_call\r\nREM Remote Procedure Call (RPC)\r\n2>nul sc query | find /i \"SERVICE_NAME: RpcSs\" \r\nif not errorlevel 1 (goto security_accounts_manager) else goto start_rpc_service\r\n\r\n:start_rpc_service\r\n2>nul sc config RpcSs start= AUTO\r\n2>nul net start RpcSs\r\n\r\n:security_accounts_manager\r\nREM Security Accounts Manager\r\n2>nul sc query | find /i \"SERVICE_NAME: SamSs\"\r\nif not errorlevel 1 (goto server_service) else goto start_security_service\r\n\r\n:start_security_service\r\n2>nul sc config SamSs start= AUTO\r\n2>nul net start SamSs\r\n\r\n:server_service\r\nREM Server\r\n2>nul sc query | find /i \"SERVICE_NAME: LanmanServer\"\r\nif not errorlevel 1 (goto get_sid_guest) else goto start_server_service\r\n\r\n:start_server_service\r\n2>nul sc config LanmanServer start= AUTO\r\n2>nul net start LanmanServer\r\n\r\n:get_sid_guest\r\necho get sid guest variable\r\nfor /f \"delims= \" %%a in ('powershell -command \"(Get-LocalUser | Where-Object SID -like '*-501').SID.Value\"') do (\r\n\tset \"sid_guest=%%a\"\r\n\tgoto loop_end_guest_sid\r\n)\r\n\r\n:loop_end_guest_sid\r\n\r\necho create script for regini\r\n@echo \\Registry\\Machine\\SECURITY [1 5 7 11 17 21]> x\r\n@echo \\Registry\\Machine\\SECURITY\\policy [1 5 7 11 17 21]>> x\r\n@echo \\Registry\\Machine\\SECURITY\\policy\\accounts [1 5 7 11 17 21]>> x\r\n@echo \\Registry\\Machine\\SECURITY\\policy\\accounts\\%sid_guest% [1 5 7 11 17 21]>> x\r\n@echo \\Registry\\Machine\\SECURITY\\policy\\accounts\\%sid_guest%\\ActSysAc [1 5 7 11 17 21]>> x\r\n\r\necho add permission for machine/security\r\npowershell -command \"Enable-LocalUser -SID (Get-LocalUser | Where-Object SID -like '*-501').SID\"\r\nregini x\r\ndel x\r\n@echo Windows Registry Editor Version 5.00 > y.reg\r\n@echo [HKEY_LOCAL_MACHINE\\SECURITY\\Policy\\Accounts\\%sid_guest%\\ActSysAc] >> y.reg\r\n@echo @=hex(0):42,00,00,00 >> y.reg\r\n2>nul reg import y.reg\r\ndel y.reg\r\n\r\n:: call :do_everyone_name\r\n\r\n:: delete share if target is different\r\nfor /f \"skip=1 tokens=1,2\" %%a in ('net share %netshare_target%') do (\r\n\tif /i not \"%%b\"==\"%netshare_source%\" (\r\n\t\t2>nul net share \"%netshare_target%\" /delete /y\r\n\t)\r\n\tgoto netshare_server_next\r\n)\r\n:netshare_server_next\r\n\r\nnet share %netshare_target%\r\nif %errorlevel% neq 0 (\r\n\tif exist \"%netshare_source%\" (\r\n\t\tfor /f \"tokens=1* delims= \" %%a in ('whoami /groups ^| find \"S-1-1-0\"') do ( net share %netshare_target%=\"%netshare_source%\" /unlimited /y /grant:\"%%a\",%netshare_permission% )\r\n\t)\r\n)\r\nICACLS \"%netshare_source%\" /grant:r \"*S-1-1-0\":(OI)(CI)F /inheritance:e /T\r\nexit /b 0\r\n:netshare_server_end\r\n\r\ngoto fix_win11_24H2_end\r\n:fix_win11_24H2\r\n(\r\necho Windows Registry Editor Version 5.00\r\necho.\r\necho [HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\LanmanWorkstation\\Parameters]\r\necho \"RequireSecuritySignature\"=dword:00000000\r\necho.\r\necho [HKEY_LOCAL_MACHINE\\SOFTWARE\\Policies\\Microsoft\\Windows\\LanmanWorkstation]\r\necho \"AllowInsecureGuestAuth\"=dword:00000001\r\necho.\r\necho [HKEY_LOCAL_MACHINE\\SOFTWARE\\WOW6432Node\\Policies\\Microsoft\\Windows\\LanmanWorkstation]\r\necho \"AllowInsecureGuestAuth\"=dword:00000001\r\n) > temp.reg\r\n\r\n:: Import the REG file\r\nreg import temp.reg\r\n\r\n:: Delete the temporary file\r\ndel /q temp.reg\r\nexit /b 0\r\n:fix_win11_24H2_end\r\n\r\n",
    "cmd_client": "set \"gamedrive=D:\"\r\nset \"NetShareName=iCafeCloudShare\"\r\nset \"NetShareSource=M:\\iCafeCloudShare\"\r\nset \"SaveShaders=1\"\r\nset \"GameSave=1\"\r\nset \"ICafeHDD=0\"\r\nset \"run_icafemenu_before_desktop=0\"\r\ncall :do_gamefix_permission\r\n\r\nrem ==== fix NVIDIA shaders ==== \nif not defined ServerIP goto end_nvidia_save_shaders\nif %SaveShaders% neq 1 goto end_nvidia_save_shaders\ncall :netshare_client \"%ServerIP%\"\n:: NET USE * /DELETE /Y 2>nul\n:: NET USE \"\\\\%ServerIP%\\%NetShareName%\" \"\" /USER:guest /Y\nif %errorlevel% neq 0 goto end_nvidia_save_shaders\nrem call :do_mklink \"%localappdata%\\NVIDIA\" \"DXCache\" 0 \"\\\\%ServerIP%\\%NetShareName%\\pcs\\%computername%\\NvidaDXCache\"\nrem call :do_mklink \"%localappdata%\\NVIDIA\" \"GLCache\" 0 \"\\\\%ServerIP%\\%NetShareName%\\pcs\\%computername%\\NvidaGLCache\"\n:end_nvidia_save_shaders\n\nREM ==== Clear user data ===\nif not defined ServerIP goto end_clear_save_userdata\ncall :netshare_client \"%ServerIP%\"\n\nset \"license_save_userdata_range=2\"\nset \"iCafeCloudShareDir=\\\\%ServerIP%\\%NetShareName%\"\n\nREM Using minutes is for ease of testing\nset \"license_save_user_data_expire_minutes=\"\n\nif \"%license_save_userdata_range%\"==\"0\" set /a license_save_user_data_expire_minutes=30 * 1440\nif \"%license_save_userdata_range%\"==\"1\" set /a license_save_user_data_expire_minutes=90 * 1440\nif \"%license_save_userdata_range%\"==\"3\" set /a license_save_user_data_expire_minutes=180 * 1440\nif \"%license_save_userdata_range%\"==\"4\" set /a license_save_user_data_expire_minutes=365 * 1440\n\nREM Never\nif \"%license_save_userdata_range%\"==\"2\" goto end_clear_save_userdata\n\nREM iCafeCloudShare/users/[member account][game id]\nfor %%r in (users) do (\n\tfor /d %%a in (\"%iCafeCloudShareDir%\\%%r\\*\") do (\n\t\tfor /d %%b in (\"%%a\\*\") do (\n\t\t\tREM echo [SCAN] %%b\n\t\t\tfor /f \"tokens=1,2 delims=|\" %%t in ('\n\t\t\t\tpowershell -NoProfile -Command \"$p='%%~fb';$m=(Get-Item $p).LastWriteTime;Get-ChildItem -LiteralPath $p -Recurse -Force -ErrorAction SilentlyContinue|ForEach-Object{if($_.LastWriteTime -gt $m){$m=$_.LastWriteTime}};$expired=$m -lt (Get-Date).AddMinutes(-%license_save_user_data_expire_minutes%);$m.ToString(\\\"yyyy-MM-dd HH:mm:ss\\\") + '|' + ([int]$expired)\"\n\t\t\t') do (\n\t\t\t\tREM echo [LAST] %%t\n\t\t\t\tif \"%%u\"==\"1\" (\n\t\t\t\t\tREM echo [DEL ] expired - deleting %%b\n\t\t\t\t\trmdir /s /q \"%%b\" >nul 2>&1\n\t\t\t\t) else (\n\t\t\t\t\tREM echo [KEEP] not expired\n\t\t\t\t)\n\t\t\t)\n\t\t\tREM echo.\n\t\t)\n\t)\n)\n:end_clear_save_userdata\r\n\r\nrem ==== GameFix FiveM ====\r\n\ncall :do_mklink \"%LocalAppData%\" \"FiveM\" 0 \"FiveM\\LocalAppData\"\n\r\n\r\nrem ==== GameFix Rockstar ====\r\n\ncall :do_mklink \"%LocalAppData%\" \"Rockstar Games\" 0 \"Rockstar\\APPDATA\\Local\"\ncall :do_mklink \"%ProgramData%\" \"Rockstar Games\" 0 \"Rockstar\\ProgramData\"\n\nReg.exe add \"HKLM\\SOFTWARE\\Classes\\rockstar\" /ve /t REG_SZ /d \"URL:rockstar Protocol\" /f\nReg.exe add \"HKLM\\SOFTWARE\\Classes\\rockstar\" /v \"URL Protocol\" /t REG_SZ /d \"\" /f\nReg.exe add \"HKLM\\SOFTWARE\\Classes\\rockstar\\DefaultIcon\" /ve /t REG_SZ /d \"\\\"D:\\Launchers\\Rockstar Games\\Launcher\\Launcher.exe\\\"\" /f\nReg.exe add \"HKLM\\SOFTWARE\\Classes\\rockstar\\shell\\open\\command\" /ve /t REG_SZ /d \"\\\"D:\\Launchers\\Rockstar Games\\Launcher\\Launcher.exe\\\" \\\"%%1\\\"\" /f\nIf exist \"D:\\Launchers\\Rockstar Games\\Launcher\\rockstar.reg\" ( reg.exe import \"D:\\Launchers\\Rockstar Games\\Launcher\\rockstar.reg\" /y )\n\r\n\r\nrem ==== GameFix Uplay ====\r\n\ncall :do_mklink \"%LocalAppData%\" \"Ubisoft Game Launcher\" 0 \"Uplay\\APPDATA\\Local\"\ncall :do_mklink \"%ProgramData%\" \"Ubisoft\" 0 \"Uplay\\ProgramData\"\n\nReg.exe add \"HKCR\\uplay\" /ve /t REG_SZ /d \"URL:uplay protocol\" /f\nReg.exe add \"HKCR\\uplay\" /v \"URL Protocol\" /t REG_SZ /d \"\" /f\nReg.exe add \"HKCR\\uplay\\DefaultIcon\" /ve /t REG_SZ /d \"upc.exe\" /f\nReg.exe add \"HKCR\\uplay\\Shell\\Open\\Command\" /ve /t REG_SZ /d \"\\\"K:\\ONLINE GAMES\\Uplay\\upc.exe\\\" \\\"%%1\\\"\" /f\r\n\r\nrem ==== GameFix iCafeMenu ====\r\n\r\nreg.exe add \"HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\" /f /v Userinit /t REG_SZ /d \"C:\\Windows\\system32\\userinit.exe,\"\r\nreg.exe add \"HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\" /f /v Shell /t REG_SZ /d \"explorer.exe\"\r\nif not defined ServerIP goto end_icafemenu\r\nset isServer=0\r\nfor /f \"tokens=2 delims=:\" %%i in ('ipconfig ^| findstr \"IPv4\"') do (\r\n\tif \"%%i\" equ \" %ServerIP%\" set isServer=1\r\n)\r\nIf \"%isServer%\"==\"0\" (\r\n\tif \"%run_icafemenu_before_desktop%\" == \"1\" (\r\n\t\treg.exe add \"HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\" /f /v Userinit /t REG_SZ /d \"C:\\Windows\\system32\\userinit.exe,%~dp0iCafeMenu.exe,\"\r\n\t) else (\r\n\t\treg.exe add \"HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Run\" /f /v iCafeMenu /t REG_SZ /d \"%~dp0iCafeMenu.exe\"\r\n\t)\r\n\t\r\n)\r\n\r\nif %SaveShaders% neq 1 goto end_icafemenu\r\ncall :netshare_client \"%ServerIP%\"\r\n:: NET USE \"\\\\%ServerIP%\\iCafeCloudShare\" \"\" /USER:guest /Y\r\nif %errorlevel% equ 0 (\r\n\tREM redirect icafemenu log can only source_copy = 0 else it will overwrite the old log\r\n\tcall :do_mklink \"%~dp0\" \"Log\" 0 \"\\\\%ServerIP%\\iCafeCloudShare\\pcs\\%computername%\\log\"\r\n)\r\n\r\n:end_icafemenu\r\n\r\n\r\ngoto do_mklink_end\r\n:do_mklink\r\n:: do_mklink \"source_path\" \"source_name\" \"source_copy\" \"target_path\"\r\nset \"source_path=%~1\"\r\nset \"source_name=%~2\"\r\nset \"source_copy=%~3\"\r\nset \"target_path=%~4\"\r\n:: if not absolute path\r\nIf \"%target_path:~1,1%\" equ \":\" goto mklink_next\r\nIf \"%target_path:~0,2%\" equ \"\\\\\" goto mklink_next\r\nset \"target_path=%gamedrive%\\GameFixes\\%target_path%\"\r\n:mklink_next\r\n2>nul dir /AL /B \"%source_path%\" | find \"%source_name%\"\r\nIf %errorlevel% equ 0 (\r\n\trmdir \"%source_path%\\%source_name%\"\r\n)\r\n2>nul dir /AD /B \"%source_path%\" | find \"%source_name%\"\r\nIf %errorlevel% equ 0 (\r\n\tIf %source_copy% equ 1 (\r\n\t\txcopy \"%source_path%\\%source_name%\\*\" \"%target_path%\\\" /y /s /e\r\n\t)\r\n\trmdir \"%source_path%\\%source_name%\" /s /q\r\n)\r\n\r\nIf not exist \"%target_path%\\\" ( mkdir \"%target_path%\\\" )\r\nIf exist \"%target_path%\\\" (\r\n\tif not exist \"%source_path%\\%source_name%\\\" (\r\n\t\tmkdir \"%source_path%\\%source_name%\\\"\r\n\t\trmdir \"%source_path%\\%source_name%\\\"\r\n\t)\r\n\tmklink /D \"%source_path%\\%source_name%\\\" \"%target_path%\\\"\r\n)\r\nexit /b 0\r\n:do_mklink_end\r\n\r\ngoto do_everyone_name_end\r\n:do_everyone_name\r\n:: https://groups.google.com/g/alt.msdos.batch.nt/c/__xbYef0Z_Y\r\nset \"everyone_name=Everyone\"\r\nfor /f \"tokens=1* delims= \" %%a in ('whoami /groups ^| find \"S-1-1-0\"') do ( set \"everyone_name=%%a\" )\r\n:loop_do_everyone_name_end\r\nexit /b 0\r\n:do_everyone_name_end\r\n\r\ngoto do_gamefix_permission_end\r\n:do_gamefix_permission\r\n:: call :do_everyone_name\r\nICACLS \"%gamedrive%\\GameFixes\" /grant:r \"*S-1-1-0\":(OI)(CI)F /inheritance:e /T /Q\r\nexit /b 0\r\n:do_gamefix_permission_end\r\n\r\ngoto create_desktop_shortcut_end\r\n:create_desktop_shortcut\r\nset \"shortcut_name=%~1\"\r\nset \"shortcut_exe_path=%~2\"\r\nset \"shortcut_work_path=%~3\"\r\n\r\necho On Error Resume Next > \"%~dp0CreateShortcut.vbs\"\r\necho Set WshShell = WScript.CreateObject(\"WScript.Shell\") >> \"%~dp0CreateShortcut.vbs\"\r\necho strDesktop = WshShell.SpecialFolders(\"Desktop\") >> \"%~dp0CreateShortcut.vbs\"\r\necho set oShellLink = WshShell.CreateShortcut(strDesktop ^& \"\\\" ^& \"%shortcut_name%\" ^& \".lnk\") >> \"%~dp0CreateShortcut.vbs\"\r\necho oShellLink.TargetPath = \"%shortcut_exe_path%\" >> \"%~dp0CreateShortcut.vbs\"\r\necho oShellLink.Description = \"%shortcut_name%\" >> \"%~dp0CreateShortcut.vbs\"\r\necho oShellLink.WorkingDirectory = \"%shortcut_work_path%\" >> \"%~dp0CreateShortcut.vbs\"\r\necho oShellLink.Save >> \"%~dp0CreateShortcut.vbs\"\r\n\r\ncall wscript -e:vbs \"%~dp0CreateShortcut.vbs\"\r\nexit /b 0\r\n:create_desktop_shortcut_end\r\n\r\ngoto replace_file_string_end\r\n:replace_file_string\r\nset \"file_path=%~1\"\r\nset \"file_string=%~2\"\r\nset \"file_replace=%~3\"\r\necho On Error Resume Next > \"%~dp0ReplaceFileString.vbs\"\r\necho Dim Fso, textFile, textString >> \"%~dp0ReplaceFileString.vbs\"\r\necho Set Fso = CreateObject(\"Scripting.FileSystemObject\") >> \"%~dp0ReplaceFileString.vbs\"\r\necho Set textFile = Fso.OpenTextFile(\"%file_path%\", 1) >> \"%~dp0ReplaceFileString.vbs\"\r\necho textString = Replace(textFile.ReadAll, \"%file_string%\", \"%file_replace%\") >> \"%~dp0ReplaceFileString.vbs\"\r\necho textFile.Close >> \"%~dp0ReplaceFileString.vbs\"\r\necho Set textFile = Fso.OpenTextFile(\"%file_path%\", 2) >> \"%~dp0ReplaceFileString.vbs\"\r\necho textFile.Write textString >> \"%~dp0ReplaceFileString.vbs\"\r\necho textFile.Close >> \"%~dp0ReplaceFileString.vbs\"\r\n\r\ncall wscript -e:vbs \"%~dp0ReplaceFileString.vbs\"\r\nexit /b 0\r\n:replace_file_string_end\r\n\r\n\r\ngoto netshare_client_end\r\n:netshare_client\r\nset \"server_ip=%~1\"\r\ncall :fix_win11_24H2\r\n:network_store_interface\r\nREM Network Store Interface Service for client\r\n2>nul sc query | find /i \"SERVICE_NAME: nsi\"\r\nif %errorlevel% equ 0 (\r\n\tgoto workstation_service\r\n) else (\r\n\tgoto start_nsi_service\r\n)\r\n\r\n:start_nsi_service\r\n2>nul sc config nsi start= AUTO\r\n2>nul net start nsi\r\n\r\n:workstation_service\r\nREM Workstation\r\n2>nul sc query | find /i \"SERVICE_NAME: LanmanWorkstation\"\r\nif %errorlevel% equ 0 (\r\n\tgoto netshare_exit\r\n) else (\r\n\tgoto start_workstation\r\n)\r\n\r\n:start_workstation\r\n2>nul sc config LanmanWorkstation start= AUTO\r\n2>nul net start LanmanWorkstation\r\n\r\n:netshare_exit\r\nfsutil behavior set SymlinkEvaluation L2R:1\r\npowershell -command \"cmdkey /add:%server_ip% /user:$((Get-LocalUser | Where-Object SID -like '*-501').Name)\" \r\nexit /b 0\r\n:netshare_client_end\r\n\r\ngoto netshare_server_end\r\n:netshare_server\r\nREM Netshare Required Services for server\r\n:: call :netshare_server \"source\" \"target\" \"permission\"\r\nset \"netshare_source=%~1\"\r\nset \"netshare_target=%~2\"\r\nset \"netshare_permission=%~3\"\r\n\r\nIf not exist \"%netshare_source%\" ( mkdir \"%netshare_source%\" )\r\n\r\ncall :fix_win11_24H2\r\n\r\n:rpc_endpoint_mapper\r\nREM RPC Endpoint Mapper\r\n2>nul sc query | find /i \"SERVICE_NAME: RpcEptMapper\"\r\nif not errorlevel 1 (goto dcom_server_process_launcher) else goto start_rpc_mapper_service\r\n\r\n:start_rpc_mapper_service\r\n2>nul sc config nsi start= AUTO\r\n2>nul net start nsi\r\n\r\n:dcom_server_process_launcher\r\nREM DCOM Server Process Launcher\r\n2>nul sc query | find /i \"SERVICE_NAME: DcomLaunch\"\r\nif not errorlevel 1 (goto remote_procedure_call) else goto start_dcom_service\r\n\r\n:start_dcom_service\r\n2>nul sc config DcomLaunch start= AUTO\r\n2>nul net start DcomLaunch\r\n\r\n:remote_procedure_call\r\nREM Remote Procedure Call (RPC)\r\n2>nul sc query | find /i \"SERVICE_NAME: RpcSs\" \r\nif not errorlevel 1 (goto security_accounts_manager) else goto start_rpc_service\r\n\r\n:start_rpc_service\r\n2>nul sc config RpcSs start= AUTO\r\n2>nul net start RpcSs\r\n\r\n:security_accounts_manager\r\nREM Security Accounts Manager\r\n2>nul sc query | find /i \"SERVICE_NAME: SamSs\"\r\nif not errorlevel 1 (goto server_service) else goto start_security_service\r\n\r\n:start_security_service\r\n2>nul sc config SamSs start= AUTO\r\n2>nul net start SamSs\r\n\r\n:server_service\r\nREM Server\r\n2>nul sc query | find /i \"SERVICE_NAME: LanmanServer\"\r\nif not errorlevel 1 (goto get_sid_guest) else goto start_server_service\r\n\r\n:start_server_service\r\n2>nul sc config LanmanServer start= AUTO\r\n2>nul net start LanmanServer\r\n\r\n:get_sid_guest\r\necho get sid guest variable\r\nfor /f \"delims= \" %%a in ('powershell -command \"(Get-LocalUser | Where-Object SID -like '*-501').SID.Value\"') do (\r\n\tset \"sid_guest=%%a\"\r\n\tgoto loop_end_guest_sid\r\n)\r\n\r\n:loop_end_guest_sid\r\n\r\necho create script for regini\r\n@echo \\Registry\\Machine\\SECURITY [1 5 7 11 17 21]> x\r\n@echo \\Registry\\Machine\\SECURITY\\policy [1 5 7 11 17 21]>> x\r\n@echo \\Registry\\Machine\\SECURITY\\policy\\accounts [1 5 7 11 17 21]>> x\r\n@echo \\Registry\\Machine\\SECURITY\\policy\\accounts\\%sid_guest% [1 5 7 11 17 21]>> x\r\n@echo \\Registry\\Machine\\SECURITY\\policy\\accounts\\%sid_guest%\\ActSysAc [1 5 7 11 17 21]>> x\r\n\r\necho add permission for machine/security\r\npowershell -command \"Enable-LocalUser -SID (Get-LocalUser | Where-Object SID -like '*-501').SID\"\r\nregini x\r\ndel x\r\n@echo Windows Registry Editor Version 5.00 > y.reg\r\n@echo [HKEY_LOCAL_MACHINE\\SECURITY\\Policy\\Accounts\\%sid_guest%\\ActSysAc] >> y.reg\r\n@echo @=hex(0):42,00,00,00 >> y.reg\r\n2>nul reg import y.reg\r\ndel y.reg\r\n\r\n:: call :do_everyone_name\r\n\r\n:: delete share if target is different\r\nfor /f \"skip=1 tokens=1,2\" %%a in ('net share %netshare_target%') do (\r\n\tif /i not \"%%b\"==\"%netshare_source%\" (\r\n\t\t2>nul net share \"%netshare_target%\" /delete /y\r\n\t)\r\n\tgoto netshare_server_next\r\n)\r\n:netshare_server_next\r\n\r\nnet share %netshare_target%\r\nif %errorlevel% neq 0 (\r\n\tif exist \"%netshare_source%\" (\r\n\t\tfor /f \"tokens=1* delims= \" %%a in ('whoami /groups ^| find \"S-1-1-0\"') do ( net share %netshare_target%=\"%netshare_source%\" /unlimited /y /grant:\"%%a\",%netshare_permission% )\r\n\t)\r\n)\r\nICACLS \"%netshare_source%\" /grant:r \"*S-1-1-0\":(OI)(CI)F /inheritance:e /T\r\nexit /b 0\r\n:netshare_server_end\r\n\r\ngoto fix_win11_24H2_end\r\n:fix_win11_24H2\r\n(\r\necho Windows Registry Editor Version 5.00\r\necho.\r\necho [HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\LanmanWorkstation\\Parameters]\r\necho \"RequireSecuritySignature\"=dword:00000000\r\necho.\r\necho [HKEY_LOCAL_MACHINE\\SOFTWARE\\Policies\\Microsoft\\Windows\\LanmanWorkstation]\r\necho \"AllowInsecureGuestAuth\"=dword:00000001\r\necho.\r\necho [HKEY_LOCAL_MACHINE\\SOFTWARE\\WOW6432Node\\Policies\\Microsoft\\Windows\\LanmanWorkstation]\r\necho \"AllowInsecureGuestAuth\"=dword:00000001\r\n) > temp.reg\r\n\r\n:: Import the REG file\r\nreg import temp.reg\r\n\r\n:: Delete the temporary file\r\ndel /q temp.reg\r\nexit /b 0\r\n:fix_win11_24H2_end\r\n\r\n",
    "cmd_gamesave": "set \"gamedrive=D:\"\r\nset \"NetShareName=iCafeCloudShare\"\r\nset \"NetShareSource=M:\\iCafeCloudShare\"\r\nset \"SaveShaders=1\"\r\nset \"ICafeHDD=0\"\r\nset \"GameSave=1\"\r\nset \"GameSaveLimit=0\"\r\n\r\nset \"member_account=%~1\"\nif not defined member_account goto end_game_save\nif \"%GameSave%\" neq \"1\" goto end_game_save\ncall :netshare_client \"%ServerIP%\"\n:: NET USE \"\\\\%ServerIP%\\%NetShareName%\" \"\" /USER:guest /Y\nif %errorlevel% neq 0 goto end_game_save\nif %GameSaveLimit% equ 0 goto next_game_save\n\n@echo off\nfor /f \"tokens=*\" %%a in ('chcp') do for %%b in (%%a) do set \"_codepage=%%~nb\"\nchcp 437\nset folder_size=0\nset \"gamesave_path=\\\\%ServerIP%\\%NetShareName%\\users\\%member_account%\"\nfor /f \"tokens=3* delims= \" %%a in ('2^>nul dir \"%gamesave_path%\" /a-d /s /-c ^| find /i \"File\"') do (\n\tset folder_size=%%a\n)\n@echo on\nset /a folder_size=%folder_size%/1024/1024\nif %folder_size% GTR %GameSaveLimit% ( rmdir /s /q \"%gamesave_path%\" )\nchcp %_codepage%\n\n:next_game_save\n\r\nrem Grand Theft Auto V Enhanced\r\n\r\nrem ==== GameSave for Grand Theft Auto V Enhanced ====\r\ncall :do_mklink \"%PROGRAMDATA%\" \"Socialclub\" 0 \"\\\\%ServerIP%\\iCafeCloudShare\\users\\%member_account%\\16\\%%%%PROGRAMDATA%%%%\\Socialclub\"\r\n\r\nrem Grand Theft Auto V Legacy\r\n\r\nrem ==== GameSave for Grand Theft Auto V Legacy ====\r\ncall :do_mklink \"%PROGRAMDATA%\" \"Socialclub\" 0 \"\\\\%ServerIP%\\iCafeCloudShare\\users\\%member_account%\\17\\%%%%PROGRAMDATA%%%%\\Socialclub\"\r\n\r\nrem Marvel's Spider-Man 2\r\n\r\nrem ==== GameSave for Marvel's Spider-Man 2 ====\r\ncall :do_mklink \"%LOCALAPPDATA%\\SKIDROW\\212580\" \"Storage\" 0 \"\\\\%ServerIP%\\iCafeCloudShare\\users\\%member_account%\\18\\%%%%LOCALAPPDATA%%%%\\SKIDROW\\212580\\Storage\"\r\n\r\nrem Just Cause 3\r\n\r\nrem ==== GameSave for Just Cause 3 ====\r\ncall :do_mklink \"%USERPROFILE%\\Documents\\Square Enix\\Just Cause 3\\Saves\" \"0\" 0 \"\\\\%ServerIP%\\iCafeCloudShare\\users\\%member_account%\\20826\\%%%%USERPROFILE%%%%\\Documents\\Square Enix\\Just Cause 3\\Saves\\0\"\r\n\r\nrem GOD OF WAR RAGNAROK\r\n\r\nrem ==== GameSave for GOD OF WAR RAGNAROK ====\r\ncall :do_mklink \"%userprofile%\\Saved Games\\%USERPROFILE%\\Saved Games\" \"God of War Ragnarök\" 0 \"\\\\%ServerIP%\\iCafeCloudShare\\users\\%member_account%\\22760\\%%%%userprofile%%%%\\Saved Games\\%%%%USERPROFILE%%%%\\Saved Games\\God of War Ragnarök\"\r\n\r\n\r\n:end_game_save\r\n\r\ngoto do_mklink_end\r\n:do_mklink\r\n:: do_mklink \"source_path\" \"source_name\" \"source_copy\" \"target_path\"\r\nset \"source_path=%~1\"\r\nset \"source_name=%~2\"\r\nset \"source_copy=%~3\"\r\nset \"target_path=%~4\"\r\n:: if not absolute path\r\nIf \"%target_path:~1,1%\" equ \":\" goto mklink_next\r\nIf \"%target_path:~0,2%\" equ \"\\\\\" goto mklink_next\r\nset \"target_path=%gamedrive%\\GameFixes\\%target_path%\"\r\n:mklink_next\r\n2>nul dir /AL /B \"%source_path%\" | find \"%source_name%\"\r\nIf %errorlevel% equ 0 (\r\n\trmdir \"%source_path%\\%source_name%\"\r\n)\r\n2>nul dir /AD /B \"%source_path%\" | find \"%source_name%\"\r\nIf %errorlevel% equ 0 (\r\n\tIf %source_copy% equ 1 (\r\n\t\txcopy \"%source_path%\\%source_name%\\*\" \"%target_path%\\\" /y /s /e\r\n\t)\r\n\trmdir \"%source_path%\\%source_name%\" /s /q\r\n)\r\n\r\nIf not exist \"%target_path%\\\" ( mkdir \"%target_path%\\\" )\r\nIf exist \"%target_path%\\\" (\r\n\tif not exist \"%source_path%\\%source_name%\\\" (\r\n\t\tmkdir \"%source_path%\\%source_name%\\\"\r\n\t\trmdir \"%source_path%\\%source_name%\\\"\r\n\t)\r\n\tmklink /D \"%source_path%\\%source_name%\\\" \"%target_path%\\\"\r\n)\r\nexit /b 0\r\n:do_mklink_end\r\n\r\ngoto do_everyone_name_end\r\n:do_everyone_name\r\n:: https://groups.google.com/g/alt.msdos.batch.nt/c/__xbYef0Z_Y\r\nset \"everyone_name=Everyone\"\r\nfor /f \"tokens=1* delims= \" %%a in ('whoami /groups ^| find \"S-1-1-0\"') do ( set \"everyone_name=%%a\" )\r\n:loop_do_everyone_name_end\r\nexit /b 0\r\n:do_everyone_name_end\r\n\r\ngoto do_gamefix_permission_end\r\n:do_gamefix_permission\r\n:: call :do_everyone_name\r\nICACLS \"%gamedrive%\\GameFixes\" /grant:r \"*S-1-1-0\":(OI)(CI)F /inheritance:e /T /Q\r\nexit /b 0\r\n:do_gamefix_permission_end\r\n\r\ngoto create_desktop_shortcut_end\r\n:create_desktop_shortcut\r\nset \"shortcut_name=%~1\"\r\nset \"shortcut_exe_path=%~2\"\r\nset \"shortcut_work_path=%~3\"\r\n\r\necho On Error Resume Next > \"%~dp0CreateShortcut.vbs\"\r\necho Set WshShell = WScript.CreateObject(\"WScript.Shell\") >> \"%~dp0CreateShortcut.vbs\"\r\necho strDesktop = WshShell.SpecialFolders(\"Desktop\") >> \"%~dp0CreateShortcut.vbs\"\r\necho set oShellLink = WshShell.CreateShortcut(strDesktop ^& \"\\\" ^& \"%shortcut_name%\" ^& \".lnk\") >> \"%~dp0CreateShortcut.vbs\"\r\necho oShellLink.TargetPath = \"%shortcut_exe_path%\" >> \"%~dp0CreateShortcut.vbs\"\r\necho oShellLink.Description = \"%shortcut_name%\" >> \"%~dp0CreateShortcut.vbs\"\r\necho oShellLink.WorkingDirectory = \"%shortcut_work_path%\" >> \"%~dp0CreateShortcut.vbs\"\r\necho oShellLink.Save >> \"%~dp0CreateShortcut.vbs\"\r\n\r\ncall wscript -e:vbs \"%~dp0CreateShortcut.vbs\"\r\nexit /b 0\r\n:create_desktop_shortcut_end\r\n\r\ngoto replace_file_string_end\r\n:replace_file_string\r\nset \"file_path=%~1\"\r\nset \"file_string=%~2\"\r\nset \"file_replace=%~3\"\r\necho On Error Resume Next > \"%~dp0ReplaceFileString.vbs\"\r\necho Dim Fso, textFile, textString >> \"%~dp0ReplaceFileString.vbs\"\r\necho Set Fso = CreateObject(\"Scripting.FileSystemObject\") >> \"%~dp0ReplaceFileString.vbs\"\r\necho Set textFile = Fso.OpenTextFile(\"%file_path%\", 1) >> \"%~dp0ReplaceFileString.vbs\"\r\necho textString = Replace(textFile.ReadAll, \"%file_string%\", \"%file_replace%\") >> \"%~dp0ReplaceFileString.vbs\"\r\necho textFile.Close >> \"%~dp0ReplaceFileString.vbs\"\r\necho Set textFile = Fso.OpenTextFile(\"%file_path%\", 2) >> \"%~dp0ReplaceFileString.vbs\"\r\necho textFile.Write textString >> \"%~dp0ReplaceFileString.vbs\"\r\necho textFile.Close >> \"%~dp0ReplaceFileString.vbs\"\r\n\r\ncall wscript -e:vbs \"%~dp0ReplaceFileString.vbs\"\r\nexit /b 0\r\n:replace_file_string_end\r\n\r\n\r\ngoto netshare_client_end\r\n:netshare_client\r\nset \"server_ip=%~1\"\r\ncall :fix_win11_24H2\r\n:network_store_interface\r\nREM Network Store Interface Service for client\r\n2>nul sc query | find /i \"SERVICE_NAME: nsi\"\r\nif %errorlevel% equ 0 (\r\n\tgoto workstation_service\r\n) else (\r\n\tgoto start_nsi_service\r\n)\r\n\r\n:start_nsi_service\r\n2>nul sc config nsi start= AUTO\r\n2>nul net start nsi\r\n\r\n:workstation_service\r\nREM Workstation\r\n2>nul sc query | find /i \"SERVICE_NAME: LanmanWorkstation\"\r\nif %errorlevel% equ 0 (\r\n\tgoto netshare_exit\r\n) else (\r\n\tgoto start_workstation\r\n)\r\n\r\n:start_workstation\r\n2>nul sc config LanmanWorkstation start= AUTO\r\n2>nul net start LanmanWorkstation\r\n\r\n:netshare_exit\r\nfsutil behavior set SymlinkEvaluation L2R:1\r\npowershell -command \"cmdkey /add:%server_ip% /user:$((Get-LocalUser | Where-Object SID -like '*-501').Name)\" \r\nexit /b 0\r\n:netshare_client_end\r\n\r\ngoto netshare_server_end\r\n:netshare_server\r\nREM Netshare Required Services for server\r\n:: call :netshare_server \"source\" \"target\" \"permission\"\r\nset \"netshare_source=%~1\"\r\nset \"netshare_target=%~2\"\r\nset \"netshare_permission=%~3\"\r\n\r\nIf not exist \"%netshare_source%\" ( mkdir \"%netshare_source%\" )\r\n\r\ncall :fix_win11_24H2\r\n\r\n:rpc_endpoint_mapper\r\nREM RPC Endpoint Mapper\r\n2>nul sc query | find /i \"SERVICE_NAME: RpcEptMapper\"\r\nif not errorlevel 1 (goto dcom_server_process_launcher) else goto start_rpc_mapper_service\r\n\r\n:start_rpc_mapper_service\r\n2>nul sc config nsi start= AUTO\r\n2>nul net start nsi\r\n\r\n:dcom_server_process_launcher\r\nREM DCOM Server Process Launcher\r\n2>nul sc query | find /i \"SERVICE_NAME: DcomLaunch\"\r\nif not errorlevel 1 (goto remote_procedure_call) else goto start_dcom_service\r\n\r\n:start_dcom_service\r\n2>nul sc config DcomLaunch start= AUTO\r\n2>nul net start DcomLaunch\r\n\r\n:remote_procedure_call\r\nREM Remote Procedure Call (RPC)\r\n2>nul sc query | find /i \"SERVICE_NAME: RpcSs\" \r\nif not errorlevel 1 (goto security_accounts_manager) else goto start_rpc_service\r\n\r\n:start_rpc_service\r\n2>nul sc config RpcSs start= AUTO\r\n2>nul net start RpcSs\r\n\r\n:security_accounts_manager\r\nREM Security Accounts Manager\r\n2>nul sc query | find /i \"SERVICE_NAME: SamSs\"\r\nif not errorlevel 1 (goto server_service) else goto start_security_service\r\n\r\n:start_security_service\r\n2>nul sc config SamSs start= AUTO\r\n2>nul net start SamSs\r\n\r\n:server_service\r\nREM Server\r\n2>nul sc query | find /i \"SERVICE_NAME: LanmanServer\"\r\nif not errorlevel 1 (goto get_sid_guest) else goto start_server_service\r\n\r\n:start_server_service\r\n2>nul sc config LanmanServer start= AUTO\r\n2>nul net start LanmanServer\r\n\r\n:get_sid_guest\r\necho get sid guest variable\r\nfor /f \"delims= \" %%a in ('powershell -command \"(Get-LocalUser | Where-Object SID -like '*-501').SID.Value\"') do (\r\n\tset \"sid_guest=%%a\"\r\n\tgoto loop_end_guest_sid\r\n)\r\n\r\n:loop_end_guest_sid\r\n\r\necho create script for regini\r\n@echo \\Registry\\Machine\\SECURITY [1 5 7 11 17 21]> x\r\n@echo \\Registry\\Machine\\SECURITY\\policy [1 5 7 11 17 21]>> x\r\n@echo \\Registry\\Machine\\SECURITY\\policy\\accounts [1 5 7 11 17 21]>> x\r\n@echo \\Registry\\Machine\\SECURITY\\policy\\accounts\\%sid_guest% [1 5 7 11 17 21]>> x\r\n@echo \\Registry\\Machine\\SECURITY\\policy\\accounts\\%sid_guest%\\ActSysAc [1 5 7 11 17 21]>> x\r\n\r\necho add permission for machine/security\r\npowershell -command \"Enable-LocalUser -SID (Get-LocalUser | Where-Object SID -like '*-501').SID\"\r\nregini x\r\ndel x\r\n@echo Windows Registry Editor Version 5.00 > y.reg\r\n@echo [HKEY_LOCAL_MACHINE\\SECURITY\\Policy\\Accounts\\%sid_guest%\\ActSysAc] >> y.reg\r\n@echo @=hex(0):42,00,00,00 >> y.reg\r\n2>nul reg import y.reg\r\ndel y.reg\r\n\r\n:: call :do_everyone_name\r\n\r\n:: delete share if target is different\r\nfor /f \"skip=1 tokens=1,2\" %%a in ('net share %netshare_target%') do (\r\n\tif /i not \"%%b\"==\"%netshare_source%\" (\r\n\t\t2>nul net share \"%netshare_target%\" /delete /y\r\n\t)\r\n\tgoto netshare_server_next\r\n)\r\n:netshare_server_next\r\n\r\nnet share %netshare_target%\r\nif %errorlevel% neq 0 (\r\n\tif exist \"%netshare_source%\" (\r\n\t\tfor /f \"tokens=1* delims= \" %%a in ('whoami /groups ^| find \"S-1-1-0\"') do ( net share %netshare_target%=\"%netshare_source%\" /unlimited /y /grant:\"%%a\",%netshare_permission% )\r\n\t)\r\n)\r\nICACLS \"%netshare_source%\" /grant:r \"*S-1-1-0\":(OI)(CI)F /inheritance:e /T\r\nexit /b 0\r\n:netshare_server_end\r\n\r\ngoto fix_win11_24H2_end\r\n:fix_win11_24H2\r\n(\r\necho Windows Registry Editor Version 5.00\r\necho.\r\necho [HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\LanmanWorkstation\\Parameters]\r\necho \"RequireSecuritySignature\"=dword:00000000\r\necho.\r\necho [HKEY_LOCAL_MACHINE\\SOFTWARE\\Policies\\Microsoft\\Windows\\LanmanWorkstation]\r\necho \"AllowInsecureGuestAuth\"=dword:00000001\r\necho.\r\necho [HKEY_LOCAL_MACHINE\\SOFTWARE\\WOW6432Node\\Policies\\Microsoft\\Windows\\LanmanWorkstation]\r\necho \"AllowInsecureGuestAuth\"=dword:00000001\r\n) > temp.reg\r\n\r\n:: Import the REG file\r\nreg import temp.reg\r\n\r\n:: Delete the temporary file\r\ndel /q temp.reg\r\nexit /b 0\r\n:fix_win11_24H2_end\r\n\r\n"
}

var theLocalParams = {
   "enable_proxy" : 0,
   "server_ip" : "GOOMAR-CALUMPAN"
}
